sql:
SELECT name 
FROM moves 
WHERE dps = (SELECT MAX(dps) FROM moves);

SELECT COUNT(*) AS battle_count
FROM battle_logs
WHERE move_id = 1;

SELECT most_common_target
  FROM move_statistics
  WHERE win_rate = (SELECT MAX(win_rate) FROM move_statistics);

SELECT move_id
FROM move_statistics
WHERE win_rate > 0.5;

SELECT SUM(usage_count) AS total_usage
FROM move_statistics
WHERE move_id = 1;

